import{_ as a,o as s,c as t,ag as n}from"./chunks/framework.CanvC6-R.js";const u=JSON.parse('{"title":"Variables in Bliss","description":"","frontmatter":{},"headers":[],"relativePath":"language/language_reference/variables.md","filePath":"language/language_reference/variables.md"}'),i={name:"language/language_reference/variables.md"};function l(d,e,r,o,p,c){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="variables-in-bliss" tabindex="-1">Variables in Bliss <a class="header-anchor" href="#variables-in-bliss" aria-label="Permalink to &quot;Variables in Bliss&quot;">​</a></h1><p>Variables are declared using the <code>let</code> keyword.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let &lt;name&gt;: &lt;Type&gt; = &lt;expr&gt;;</span></span></code></pre></div><p>Or declared without an initial value:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let &lt;name&gt;: &lt;Type&gt;;</span></span></code></pre></div><h2 id="scalar-types" tabindex="-1">Scalar Types <a class="header-anchor" href="#scalar-types" aria-label="Permalink to &quot;Scalar Types&quot;">​</a></h2><p>Scalar variables hold a single value. Bliss provides the following scalar types:</p><table tabindex="0"><thead><tr><th>Category</th><th>Types</th></tr></thead><tbody><tr><td>Signed integers</td><td><code>i8</code>, <code>i16</code>, <code>i32</code>, <code>i64</code></td></tr><tr><td>Unsigned integers</td><td><code>u8</code>, <code>u16</code>, <code>u32</code>, <code>u64</code></td></tr><tr><td>Floating point</td><td><code>f32</code>, <code>f64</code></td></tr><tr><td>Boolean</td><td><code>bool</code> — valid values are <code>true</code> and <code>false</code></td></tr></tbody></table><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let age: u8 = 21;</span></span>
<span class="line"><span>let temperature: f32 = 36.6;</span></span>
<span class="line"><span>let active: bool = true;</span></span></code></pre></div><h2 id="arrays" tabindex="-1">Arrays <a class="header-anchor" href="#arrays" aria-label="Permalink to &quot;Arrays&quot;">​</a></h2><p>Arrays hold a sequence of values of the same type. In Bliss, arrays are <strong>fixed in size</strong> and cannot be resized once created.</p><p>There are two ways to declare an array:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let name: Type[] = [];        // initialized with values</span></span>
<span class="line"><span>let name: Type[size];         // pre-defined size, uninitialized</span></span></code></pre></div><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let scores: u8[] = [ 10, 20, 30 ];</span></span>
<span class="line"><span>let buffer: u8[256];</span></span></code></pre></div><h3 id="array-assignment" tabindex="-1">Array Assignment <a class="header-anchor" href="#array-assignment" aria-label="Permalink to &quot;Array Assignment&quot;">​</a></h3><p>Individual elements can be assigned using an index:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>arr[index] = 10;</span></span></code></pre></div><p>If the index is out of bounds, Bliss raises an <strong>unrecoverable error</strong>. Because array assignment is a statement and not an expression, it does not resolve into a <code>Result</code> — there is no way to handle or recover from the failure.</p><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h2><ul><li>A type annotation is always required.</li><li>The initializer expression is optional — a variable can be declared without one, leaving it unassigned.</li><li>When provided, the expression must evaluate to a value compatible with the declared type.</li><li>Arrays are fixed — their size cannot change after creation.</li><li>Out-of-bounds array assignment is an unrecoverable error.</li></ul><h2 id="reassignment" tabindex="-1">Reassignment <a class="header-anchor" href="#reassignment" aria-label="Permalink to &quot;Reassignment&quot;">​</a></h2><p>A variable can be reassigned after declaration using <code>=</code>:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x = 10;</span></span>
<span class="line"><span>active = false;</span></span></code></pre></div><p>Compound assignment operators are <strong>not</strong> valid in Bliss:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x += 1;  // ❌ invalid</span></span>
<span class="line"><span>x -= 1;  // ❌ invalid</span></span></code></pre></div><p>Use a full reassignment instead:</p><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x = x + 1;  // ✅</span></span>
<span class="line"><span>x = x - 1;  // ✅</span></span></code></pre></div><h2 id="syntax-reference" tabindex="-1">Syntax Reference <a class="header-anchor" href="#syntax-reference" aria-label="Permalink to &quot;Syntax Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Part</th><th>Required?</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>✅</td><td>The variable&#39;s identifier</td></tr><tr><td><code>: Type</code></td><td>✅</td><td>The variable&#39;s type</td></tr><tr><td><code>= &lt;expr&gt;</code></td><td>❌</td><td>Initial value; any expression of the matching type</td></tr><tr><td><code>Type[]</code></td><td>✅</td><td>Array of <code>Type</code>, initialized with values</td></tr><tr><td><code>Type[size]</code></td><td>✅</td><td>Array of <code>Type</code> with a pre-defined fixed size</td></tr><tr><td><code>arr[index] = &lt;expr&gt;</code></td><td>—</td><td>Assigns a value to an array element; out-of-bounds is unrecoverable</td></tr></tbody></table>`,30)])])}const b=a(i,[["render",l]]);export{u as __pageData,b as default};
